[package]
name = "web-sw-cor24-tinyc"
version = "0.1.0"
edition = "2024"

[dependencies]
yew = { version = "0.21", features = ["csr"] }
wasm-bindgen = "0.2"
wasm-bindgen-futures = "0.4"
gloo-net = { version = "0.5", features = ["http"] }
gloo-timers = "0.3"
web-sys = { version = "0.3", features = ["HtmlElement", "HtmlTextAreaElement", "HtmlSelectElement", "KeyboardEvent"] }

# tc24r compiler pipeline (C → COR24 assembly)
tc24r-span = { path = "../sw-cor24-tinyc/components/core/crates/tc24r-span" }
tc24r-preprocess = { path = "../sw-cor24-tinyc/components/frontend/crates/tc24r-preprocess" }
tc24r-lexer = { path = "../sw-cor24-tinyc/components/frontend/crates/tc24r-lexer" }
tc24r-parser = { path = "../sw-cor24-tinyc/components/frontend/crates/tc24r-parser" }
tc24r-codegen = { path = "../sw-cor24-tinyc/components/backend/crates/tc24r-codegen" }

# cor24 assembler + emulator (assembly → machine code → execution)
cor24-emulator = { path = "../sw-cor24-emulator", default-features = false }

use crate::config::ForthTier;

pub struct Demo {
    pub title: &'static str,
    pub description: &'static str,
